SELECT COUNT(*)
FROM USERS
WHERE USER_ID = #{userId}

SELECT COUNT(*)
FROM USERS
WHERE NICKNAME = #{nickname}

SELECT PASSWORD
FROM USERS
WHERE USER_ID = #{userId}

SELECT U.USER_ID, U.LEVEL_ID, U.AVATAR_ID, U.NICKNAME, U.PASSWORD, U.REG_DATE, U.EXP, U.IS_DELETE, U.GENDER,
/* 개인전 승리 */ ( SELECT COUNT(*) FROM JOIN_BATTLE JB JOIN BATTLE B ON JB.BATTLE_ID = B.BATTLE_ID WHERE JB.USER_ID = U.USER_ID AND JB.WIN_STATUS = 'WIN' AND B.MODE = 'SOLO' ) AS SOLO_WIN_COUNT,
/* 팀전 승리 */ ( SELECT COUNT(*) FROM JOIN_BATTLE JB2 JOIN BATTLE B2 ON JB2.BATTLE_ID = B2.BATTLE_ID WHERE JB2.USER_ID = U.USER_ID AND JB2.WIN_STATUS = 'WIN' AND B2.MODE = 'TEAM' ) AS TEAM_WIN_COUNT,
/* 개인전 패배 */ ( SELECT COUNT(*) FROM JOIN_BATTLE JB3 JOIN BATTLE B3 ON JB3.BATTLE_ID = B3.BATTLE_ID WHERE JB3.USER_ID = U.USER_ID AND JB3.WIN_STATUS = 'LOSE' AND B3.MODE = 'SOLO' ) AS SOLO_LOSE_COUNT,
/* 팀전 패배 */ ( SELECT COUNT(*) FROM JOIN_BATTLE JB4 JOIN BATTLE B4 ON JB4.BATTLE_ID = B4.BATTLE_ID WHERE JB4.USER_ID = U.USER_ID AND JB4.WIN_STATUS = 'LOSE' AND B4.MODE = 'TEAM' ) AS TEAM_LOSE_COUNT
FROM USERS U WHERE U.USER_ID = #{userId} AND U.IS_DELETE = 0

